#include<bits/stdc++.h>
#define int long long
using namespace std;
int ans,a[100010],b[100010];
bool vis[100010];
signed main()
{
    int n;
    scanf("%lld",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
    }
    memcpy(b,a,sizeof(a));
    sort(b+1,b+1+n);
    for(int i=1;i<=n;i++)
    {
        a[i]=lower_bound(b+1,b+1+n,a[i])-b;
    }
    for(int i=1;i<=n;i++)
    {
        if(!vis[i])
        {
            int sum=0,cnt=0,min1=INT_MAX;
            while(!vis[i])
            {
                cnt++;
                sum+=b[i];
                min1=min(min1,b[i]);
                vis[i]=1;
                i=a[i];
            }
            int ans1=(cnt-2)*min1+sum;
            int ans2=(b[1]+min1)*2+(cnt-1)*b[1]+(sum-min1);
            ans+=min(ans1,ans2);
        }
    } 
    printf("%lld",ans);
    return 0;
}
